import { useEffect, useState } from "react";
import api from "../api";
import { toast } from "react-toastify";

// Tập role hệ thống — giữ giống backend
const SYSTEM = new Set(["ADMIN","SALES","ACCOUNTANT"]);

const extractMsg = (err) =>
    err?.response?.data?.message || err?.message || "Thao tác thất bại";

export default function RoleManagerModal({ open, onClose }) {
    const [roles, setRoles] = useState([]);
    const [rename, setRename] = useState({ id: null, name: "" });

    const load = async () => {
        const res = await api.get("/api/roles");
        setRoles(res.data || []);
    };

    useEffect(() => {
        if (open) load();
    }, [open]);

    const canDelete = (r) =>
        !SYSTEM.has((r.name || "").toUpperCase()) &&
        Number(r.userCount || 0) === 0;

    const onStartRename = (r) => setRename({ id: r.id, name: r.name });

    const onSubmitRename = async () => {
        try {
            await api.put(`/api/roles/${rename.id}`, { name: rename.name.trim() });
            toast.success("Đã cập nhật vai trò");
            setRename({ id: null, name: "" });
            load();
        } catch (err) {
            toast.error(extractMsg(err));
        }
    };

    const onDelete = async (r) => {
        if (!canDelete(r)) {
            toast.error(
                SYSTEM.has((r.name || "").toUpperCase())
                    ? "Không được xoá vai trò hệ thống"
                    : `Không thể xoá vì đang có ${r.userCount} người dùng`
            );
            return;
        }
        try {
            await api.delete(`/api/roles/${r.id}`);
            toast.success("Đã xoá vai trò");
            load();
        } catch (err) {
            toast.error(extractMsg(err));
        }
    };

    if (!open) return null;

    return (
        <div className="fixed inset-0 bg-black/30 flex items-center justify-center">
            <div className="bg-white rounded-lg w-[720px] p-4 max-h-[80vh] overflow-auto">
                <div className="flex items-center justify-between mb-3">
                    <div className="text-lg font-semibold">Quản lý vai trò</div>
                    <button onClick={onClose}>Đóng</button>
                </div>

                <table className="min-w-full border">
                    <thead>
                    <tr className="bg-gray-50">
                        <th className="p-2 border">Tên vai trò</th>
                        <th className="p-2 border">Đang được dùng</th>
                        <th className="p-2 border">Thao tác</th>
                    </tr>
                    </thead>
                    <tbody>
                    {roles.map((r) => (
                        <tr key={r.id} className="border-b">
                            <td className="p-2 border">{r.name}</td>
                            <td className="p-2 border">{r.userCount ?? 0}</td>
                            <td className="p-2 border">
                                <button
                                    className={`px-2 py-1 ${
                                        SYSTEM.has((r.name || "").toUpperCase())
                                            ? "text-gray-400 cursor-not-allowed"
                                            : "text-blue-600"
                                    }`}
                                    onClick={() => onStartRename(r)}
                                    disabled={SYSTEM.has((r.name || "").toUpperCase())}
                                >
                                    Sửa
                                </button>
                                <button
                                    className={`px-2 py-1 ${
                                        canDelete(r)
                                            ? "text-red-600"
                                            : "text-gray-400 cursor-not-allowed"
                                    }`}
                                    onClick={() => onDelete(r)}
                                    disabled={!canDelete(r)}
                                >
                                    Xoá
                                </button>
                            </td>
                        </tr>
                    ))}
                    </tbody>
                </table>

                {rename.id && (
                    <div className="mt-4 p-3 border rounded">
                        <div className="font-medium mb-2">Đổi tên vai trò</div>
                        <div className="flex gap-2">
                            <input
                                className="border p-2 rounded flex-1"
                                value={rename.name}
                                onChange={(e) =>
                                    setRename((s) => ({ ...s, name: e.target.value }))
                                }
                            />
                            <button
                                className="px-3 py-2"
                                onClick={() => setRename({ id: null, name: "" })}
                            >
                                Hủy
                            </button>
                            <button
                                className="px-3 py-2 bg-indigo-600 text-white rounded"
                                onClick={onSubmitRename}
                            >
                                Lưu
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}
